solutions.javascript:
// Solution
app.use('/users', (req, res) => {
    const userId = req.params.id || req.query.id;
    const productName = req.query.name || req.body.name;
    // Handle the request here
    if (userId && productName) {
        res.json({ response: `User with ID ${userId} and product name ${productName} found.` });
    } else if (userId) {
        res.json({ response: `User with ID ${userId} found.` });
    } else if (productName) {
        res.json({ response: `Product with name ${productName} found.` });
    } else {
        res.json({ response: 'User or product not found.' });
    }
});
